17	
18	/**
19	 * Module-level flag for the mirror tool "Copy" option.
20	 * Exported so PlanCanvas can read it without a Zustand store change.
21	 * Defaults to true (keep original + add mirrored copy).
22	 */
23	export let mirrorCopyEnabled = true;
24	
25	/**
26	 * Module-level flag for the copy tool "Multiple copies" option (F-116).
27	 * When true (default) the tool stays active after each copy for multi-copy mode.
28	 * When false a single copy is placed and the tool returns to select.
29	 * Exported so PlanCanvas can read it at click-time.
30	 */
31	export let copyMultipleEnabled = true;
32	
33	/**
34	 * Module-level selected asset ID for the component placement tool.
35	 * Exported so PlanCanvas can read it on click without a Zustand store change.
36	 */
37	export let activeComponentAssetId: string | null = null;
38	export function setActiveComponentAssetId(v: string | null): void {
39	  activeComponentAssetId = v;
40	  if (!v || activeComponentAssetPreviewEntry?.id !== v) {
41	    activeComponentAssetPreviewEntry = null;
42	  }
43	}
44	
45	export let activeComponentAssetPreviewEntry: Extract<
46	  Element,
47	  { kind: 'asset_library_entry' }
48	> | null = null;
49	export function setActiveComponentAssetPreviewEntry(
50	  entry: Extract<Element, { kind: 'asset_library_entry' }> | null,
51	): void {
52	  activeComponentAssetPreviewEntry = entry;
53	  if (entry) activeComponentAssetId = entry.id;
54	}
55	
56	/**
57	 * Module-level selected family_type ID for loaded-family placement.
58	 * This shares the component placement tool with asset placement but emits
59	 * `placeFamilyInstance` instead of `PlaceAsset`.
60	 */
61	export let activeComponentFamilyTypeId: string | null = null;
62	export function setActiveComponentFamilyTypeId(v: string | null): void {
63	  activeComponentFamilyTypeId = v;
64	}
65	
66	/**
67	 * Module-level pending rotation for the component placement tool.
68	 * Spacebar in PlanCanvas increments this by 90° (mod 360).
69	 * Read at click-time by PlanCanvas and passed to PlaceAsset.
70	 * Reset to 0 when the tool changes away from 'component'.
71	 */
72	export let pendingComponentRotationDeg = 0;
73	export function setPendingComponentRotationDeg(v: number): void {
74	  pendingComponentRotationDeg = v;
75	}
76	
77	export function OptionsBar({
78	  activeTool,
79	}: {
80	  activeTool?: PlanTool | null;
81	} = {}): JSX.Element | null {
82	  const storePlanTool = useBimStore((s) => s.planTool);
83	  const planTool = activeTool ?? storePlanTool;
84	  const elementsById = useBimStore((s) => s.elementsById);
85	  const wallLocationLine = useBimStore((s) => s.wallLocationLine);
86	  const setWallLocationLine = useBimStore((s) => s.setWallLocationLine);
