88	  const setFloorBoundaryOffsetMm = useBimStore((s) => s.setFloorBoundaryOffsetMm);
89	  const wallDrawOffsetMm = useBimStore((s) => s.wallDrawOffsetMm);
90	  const setWallDrawOffsetMm = useBimStore((s) => s.setWallDrawOffsetMm);
91	  const wallDrawRadiusMm = useBimStore((s) => s.wallDrawRadiusMm);
92	  const setWallDrawRadiusMm = useBimStore((s) => s.setWallDrawRadiusMm);
