96	  const setActiveWallTypeId = useBimStore((s) => s.setActiveWallTypeId);
97	  const activeFloorTypeId = useBimStore((s) => s.activeFloorTypeId);
98	  const setActiveFloorTypeId = useBimStore((s) => s.setActiveFloorTypeId);
99	  const applyAreaRules = useBimStore((s) => s.applyAreaRules);
100	  const setApplyAreaRules = useBimStore((s) => s.setApplyAreaRules);
