107	      if (e.key === 'Escape') setShowComputations(false);
108	    };
109	    window.addEventListener('keydown', handler);
110	    return () => window.removeEventListener('keydown', handler);
111	  }, [showComputations]);
112	
113	  useEffect(() => {
114	    if (planTool !== 'component' || !activeComponentAssetId) return;
115	    const asset = elementsById[activeComponentAssetId];
116	    if (asset?.kind === 'asset_library_entry') {
117	      setActiveComponentAssetPreviewEntry(asset);
118	    }
119	  }, [elementsById, planTool]);
120	
121	  if (planTool === 'wall') {
122	    return (
123	      <div data-testid="options-bar" className={BAR_CLASS}>
124	        <label className="flex items-center gap-2">
125	          <span className="text-muted">Type:</span>
126	          <select
127	            value={activeWallTypeId ?? ''}
128	            onChange={(e) => setActiveWallTypeId(e.target.value || null)}
129	            className="rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
130	            aria-label="Wall type"
131	            data-testid="options-bar-wall-type"
132	          >
133	            <option value="">(Default)</option>
134	            {Object.values(elementsById)
135	              .filter((e): e is Extract<Element, { kind: 'wall_type' }> => e.kind === 'wall_type')
136	              .map((t) => (
137	                <option key={t.id} value={t.id}>
138	                  {t.name}
139	                </option>
140	              ))}
141	          </select>
142	        </label>
143	        <span className="text-muted">Location Line:</span>
144	        <select
145	          value={wallLocationLine}
146	          onChange={(e) => setWallLocationLine(e.target.value as WallLocationLine)}
147	          className="rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
148	          aria-label="Wall location line"
149	        >
150	          {WALL_LOCATION_LINE_ORDER.map((loc) => (
151	            <option key={loc} value={loc}>
152	              {LOCATION_LINE_LABELS[loc]}
153	            </option>
154	          ))}
155	        </select>
156	        <span className="text-muted opacity-60">Tab to cycle</span>
157	        <label className="flex items-center gap-2">
158	          <span className="text-muted">Offset:</span>
159	          <input
160	            type="number"
161	            value={wallDrawOffsetMm}
162	            step={50}
163	            onChange={(e) => setWallDrawOffsetMm(Number(e.target.value))}
164	            className="w-20 rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
165	            aria-label="Wall baseline offset in mm"
166	            data-testid="options-bar-wall-offset"
167	          />
168	          <span className="text-muted opacity-60">mm</span>
169	        </label>
170	        <label className="flex items-center gap-2">
171	          <span className="text-muted">Height:</span>
172	          <input
173	            type="number"
174	            value={wallDrawHeightMm}
175	            step={100}
176	            min={100}
177	            onChange={(e) => setWallDrawHeightMm(Number(e.target.value))}
178	            className="w-20 rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
179	            aria-label="Wall height in mm"
180	            data-testid="options-bar-wall-height"
181	          />
182	          <span className="text-muted opacity-60">mm</span>
