1	import { describe, expect, it } from 'vitest';
2	import { gridLineIntersection, columnPositionsAtGridIntersections } from './columnAtGrids';
3	import type { Element } from '@bim-ai/core';
4	
5	type GridLineElem = Extract<Element, { kind: 'grid_line' }>;
6	
7	function makeGrid(id: string, x1: number, y1: number, x2: number, y2: number): GridLineElem {
8	  return {
9	    kind: 'grid_line',
10	    id,
11	    name: id,
12	    label: id,
13	    start: { xMm: x1, yMm: y1 },
14	    end: { xMm: x2, yMm: y2 },
15	  };
16	}
17	
18	describe('gridLineIntersection', () => {
19	  it('finds intersection of horizontal and vertical grid lines', () => {
20	    const h = makeGrid('H', 0, 3000, 10000, 3000);
21	    const v = makeGrid('V', 5000, 0, 5000, 10000);
22	    const pt = gridLineIntersection(h, v);
23	    expect(pt).not.toBeNull();
24	    expect(pt!.xMm).toBeCloseTo(5000, 3);
25	    expect(pt!.yMm).toBeCloseTo(3000, 3);
26	  });
27	
28	  it('returns null for parallel grid lines', () => {
29	    const h1 = makeGrid('H1', 0, 0, 10000, 0);
30	    const h2 = makeGrid('H2', 0, 3000, 10000, 3000);
31	    expect(gridLineIntersection(h1, h2)).toBeNull();
32	  });
33	});
34	
35	describe('columnPositionsAtGridIntersections', () => {
36	  it('3×3 grid produces 9 intersection points', () => {
37	    const grids: GridLineElem[] = [
38	      makeGrid('H1', 0, 0, 12000, 0),
39	      makeGrid('H2', 0, 4000, 12000, 4000),
40	      makeGrid('H3', 0, 8000, 12000, 8000),
41	      makeGrid('V1', 0, 0, 0, 12000),
42	      makeGrid('V2', 4000, 0, 4000, 12000),
43	      makeGrid('V3', 8000, 0, 8000, 12000),
44	    ];
45	    const pts = columnPositionsAtGridIntersections(grids);
46	    expect(pts.length).toBe(9);
47	  });
48	
49	  it('2 lines produce exactly 1 intersection', () => {
50	    const grids: GridLineElem[] = [
51	      makeGrid('H', 0, 5000, 10000, 5000),
52	      makeGrid('V', 5000, 0, 5000, 10000),
53	    ];
54	    const pts = columnPositionsAtGridIntersections(grids);
55	    expect(pts.length).toBe(1);
56	    expect(pts[0]!.xMm).toBeCloseTo(5000, 3);
57	  });
58	
59	  it('deduplicates near-coincident intersections', () => {
60	    // Three lines meeting at a single point
61	    const grids: GridLineElem[] = [
62	      makeGrid('A', 0, 5000, 10000, 5000),
63	      makeGrid('B', 5000, 0, 5000, 10000),
64	      makeGrid('C', 0, 0, 10000, 10000),
