import { cleanup, render, screen, fireEvent } from '@testing-library/react';
import { afterEach, describe, it, expect, vi, beforeEach } from 'vitest';
import { ANNOTATION_CATEGORIES, MODEL_CATEGORIES, VVDialog } from './VVDialog';

// Mock useBimStore
const mockSetCategoryOverride = vi.fn();
const mockStore = {
  activePlanViewId: 'pv-1',
  elementsById: {
    'pv-1': {
      kind: 'plan_view',
      id: 'pv-1',
      name: 'Level 1 Floor Plan',
      levelId: 'lv-1',
      categoryOverrides: {},
    },
  },
  setCategoryOverride: mockSetCategoryOverride,
};

vi.mock('../../state/store', () => ({
  useBimStore: (selector: (s: typeof mockStore) => unknown) => selector(mockStore),
}));

afterEach(() => {
