        .map((v) => ({
          id: v.id,
          label: v.name,
          icon: OrbitViewIcon,
          hint: v.kind === 'saved_view' ? 'saved 3D snapshot' : 'saved camera',
          renamable: true,
        })),
    },
    {
      id: 'sections',
      label: 'Sections',
